INSERT OR IGNORE INTO posts (id, bbsid, board_id, user_id, title, content, content_text, signature, posted_at, reply_count, source_file, wayback_ts) VALUES (25, 126347, 3, 74, '《少林足球》(Shaolin Soccer)研究', '��������������������������������������首都高校周星星电影研究会  
<br>　　������������������������������会长：北京赌圣，Rollingboy  
<br>　　这个暑假，真是大片多多，好片如云，而且卖盗版的小贩们很有敬业精神，他们盗版的电影不光档期同步，做工精美，最重要的是价格公道，童叟无欺，使我们这帮喜欢享受半价优惠的穷学生有了提高文化品位，过幸福生活（简称过幸生活，下同）的机会。  
<br>　　SO，这些大片――《木乃伊&#183;二》、《古墓丽影》、《珍珠港》、《最终幻想》、《龙之吻》、《瘦身男女》、《我的兄弟姐妹》、《少林足球》等等――都凑钱买了看过了，感觉如下：前四部除了惊奇于其high-tech制作外，没啥感觉；《龙之吻》的感觉就像《卧虎藏龙》一样，在歪曲chinese-kongfu的真谛；《瘦身男女》里的歌曲刘德华伯伯唱的有一套；《我的兄弟姐妹》倒是让我这个大男生哭的稀里哗啦，但看了第二、第三遍后就使我有了好了伤疤忘了痛的感觉――麻木了，可见该片挖掘不够；《少林足球》是不错地（读di，下同），是周星星继《大话西游》近几年来少有地精品，看了以后给人以在无聊地暑假里过一过幸生活地舒服，于是又看了N遍，原因请看下一段。  
<br>　　先讲《少林足球》地好处。  
<br>　　首先，从整体来看，这部电影中心明确、结构严谨、语言朴实、条理清晰、反映民生、老幼咸宜。因此，这部电影合乎受过正统学校教育有一定知识层次地同志地欣赏品位，不会被批判地上纲上线。  
<br>　　为了方便未看过该片地同学研究该片，特把该片地中心思想陈述如下：年轻时被人陷害而踢假球被打瘸腿二十年后被赶出球队地足球教练明锋（吴孟达饰）遇上了对武术推广极度痴迷地前少林俗家弟子大力金刚腿拾荒者星（周星驰饰），二者惺惺相惜，于是组成了由明锋任教练，包含星及其少林师兄弟六人和一帮被星师兄弟六人折服地足球痞子地“少林足球队”。少林队凭借其精湛地和武术结合地球艺，一路过关斩将，顺利进入决赛，成为一匹黑驴。决赛中面对地是二十年前陷害明锋地强雄（谢贤饰）带领地“魔鬼队”。由于魔鬼队集体服用禁药，队员各个力大无比，再加上所有裁判都被强雄贿赂而偏袒魔鬼队，战斗极为惨烈。上半场结束，少林队球员由于被踢成重伤，只剩下了八人。下半场开场没多久，由后卫所担当的首门员也被踢成重伤。这样少林队只剩下七人，按规定无法继续比赛。眼看无望，这时，以前以太极功夫做“甜在心馒头”喜欢星后被星气走地阿梅（赵薇饰）以光头及时出现，并利用太极功夫地以柔克刚化解了魔鬼队地必杀进球。星利用阿梅传来地螺旋高速球并以一记大力旋转金刚连环腿踢出，终于赢得了比赛。强雄最终受到了法律地制裁而入狱五载并被终身禁赛。星和阿梅最终结为伉俪，从此大陆掀起了习练功夫地高潮，大家都过上了幸生活。  
<br>　　因为较为正统和大团圆结局可能会遭到否定一切标榜为新新新人类地美眉、崇日媚韩地哥哥们地破口大骂。不过，周星星不怕后世有千千万万地人对他唾骂，他一个人承担下去，你们就骂吧，不要再犹豫了，曾经有一个骂他地机会放在你地面前……  
<br>　　其次，从细微处看，该片不光灯光、音响、道具、茶水准备充分，而且背景、音乐、新人、编剧也值得称赞。比如它地背景音乐地选取就比较大气，很国际化，周星星以前地电影就没有这种类型地音乐，周星星看来是要真地想走向国际了；而且主题曲是刘德华大叔唱地，可能会得到追星族们地票房支持。再比如其编剧摆脱了周星星以前电影地庸俗搞笑，但也没有了以前地笑过之后地辛酸感，给人以精神百倍，彻底放松地愉悦，毕竟现在不像前几年了，现在已经是竞争激烈地网络时代了，这样地编剧使没有一点文化而又自大地商业化地老美们也能看地懂了，有助于影片进军好来坞。又比如该片地人物选取也可圈可点：反一号邀请地是近几年红地烂了街地谢霆锋地老爹人称谢四爷地谢贤，谢贤出道甚久，在亚洲有一定的知名度，演技自然无可厚非；女一号赵薇自不用说，你们一定比我还了解她，该片中和面功夫与补鞋技术跟她地光头一样靓；女二号李卉地走姿真是天下第一，其摔倒地姿式和表情也是无与伦比地，让人仿佛又看到了一颗新星地冉冉升起；周星星地几个师兄弟演的还可以，特别是那个长地像李小龙地同学，而且魔鬼队地前锋和守门员简直酷毙了等等。可见，一部好地大片好就好在其处处都好，就像王家卫电影一样。对了，玉面双飞龙也出现了，是星爷以前地绯闻女友莫文蔚和张柏芝所扮演地。  
<br>　　最后，着重讲讲该片地武术企画和设计。愚以为以足球地方式演绎武术有助于改变老外们对武术地错误认识――中国功夫是黑社会地野蛮地血腥地江湖仇杀，中国人练武术是为了强身健体，而非称霸江湖，可以驳斥所谓地“中国威胁论”；以足球地方式演绎武术有助于武术地推广，使之成为奥运项目，中国以及东南亚华人可以多得金牌，也算是告慰已故地华山、武当、峨眉派等地武术泰斗们；足球和武术相结合地创意，有助于增强中国球迷对国家队地信心。该片地武术设计真是独孤求败，别出心裁。武术导演乃香港有名地武术家程小东，他对武术地阐释显然比李安高明地多，他的武术设计颇受好评，该片地成功也算是为华人争了光，暂时地摆脱了《卧虎藏龙》带来地歪曲武术地理解。程小东地动作设计显然是把金庸武侠小说武功地物质第一性和古龙小说武功地精神第一性有机地融合了起来，使其中地武打既华丽精彩而又简捷迅速，不致于让人感到乏味和不知所云，不禁让人眼前猛的一亮。比如对太极拳术地演绎，如行云流水一般，体现了金庸功夫地大气磅礴、天人和一，让人感到心旷神怡；而对少林其他拳法地演绎有如电光火石般地迅速，体现了古龙功夫地惊心动魄、一招定输赢，让人感到酣畅淋漓。该片又运用了电脑特技，使武术处理地更加pop，有助于外国人地理解，也让那些鼠目寸光的老外们看到华人地电影不只是靠愚昧（张艺谋）、另类（张元）、个性（王家卫）、反叛（姜文）等取胜，现在国际上通行地电影手法华人也运用地也信手拈来、游刃有余。从伪武侠地成功到真武侠地成功，显示了劳动人民地眼睛是雪亮地，是不可愚弄地！从电影到文学，再从科技到体育，我们取得了一系列地成功，由此，轻视华人文化地日子一去不复返了！   
<br>　　再讲该片地不足之处。（阐释不足之处时，不再用di的读音）  
<br>　　第一，周星星没有深入群众，因此该片有点形而上学。比如，一口袋的垃圾不可能只卖两毛钱。据我调查，北京地区小贩入户收破烂的价格大致如下：一个卖五分，一个卖一毛。光矿泉水瓶、易拉罐就不只卖两毛钱，况且口袋里还有那么多别的花花草草。也许，星爷的认识仅停留在改革开放初期，忽视了最近二十年内地经济的迅猛发展，垃圾也涨价了。忽略物质世界的运动性，典型的形而上学。  
<br>　　第二，周星星的以前的电影一向爱幻想，这次也不例外，所以就导致了对生活的主观唯心主义的臆测。比如影片中的香蕉皮，在上海这样的大都市，不可能随地都是香蕉皮。他没有注意内地对环境的大力治理，认识太片面。北京申奥幸好已经成功，不然他的反面宣传会起到极其恶劣的效果。  
<br>　　第三，周星星唯英雄论，忽略了群众在历史创造中的作用。比如，该片中口口声声天下武功出少林，其实，少林只不过是集天下武功之大成而已，少林的每一项绝技都是各大门派弟子呕心沥血的结晶，他们才是历史的真正创造者。再比如，周星星妄图只靠一项绝技就能在短时间内使全民族的身体素质大幅度提高，而去忽略其他体育运动的功效，这也是唯英雄论的一种，叫唯武器论。毛主席他老人家曾教导我们：帝国主义及一切反动派都是纸老虎；决定战争结果的因素是人，而不是武器！  
<br>　　由上述三点，可见，周星星这个红小鬼需要加强理论学习，不能让不良的思想侵袭健康的躯体。身体是革命的本钱，只有有了强健的躯体，才能更好的为广大人民群众服务。  
<br>　　综上所述，这部片子还是不错地，毕竟它带给了我们欢笑与惊喜。即使你骂它，那也说明它吸引了你，最怕的就是你麻木不仁。不过，世界上还有三分之二的人民生活在看不到周星星电影的水深火热中，那就让我们更多的关注周星星，为其摇旗呐喊助威，以便使其电影更加真实的反映老百姓的生活，体现老外们的enjoy one’s life的本质，从而博得世界人民的赞赏。我们相信：周星星是最好地，是一定能行地，一切问题都只是时间。让我们拭目以待周星星电影地国际化吧！', '��������������������������������������首都高校周星星电影研究会

